framework_css:
/*
  Global design system for Industrial Cement & Lime Manufacturer
  Matches the boxed, corporate layout and header/footer style from the reference design.
*/

:root {
  /* Brand colors */
  --color-primary-main: #f58220; /* strong orange */
  --color-primary-contrast: #ffffff;

  /* Secondary / corporate */
  --color-secondary-navy: #004b87;
  --color-secondary-light-grey: #e5e5e5;

  /* Neutrals */
  --color-neutral-white: #ffffff;
  --color-neutral-page-bg: #d9d9d9; /* outer gutters */
  --color-neutral-panel: #f5f5f5;
  --color-neutral-border: #cccccc;
  --color-neutral-text: #444444;
  --color-neutral-text-muted: #777777;

  /* Semantic */
  --color-success: #2e7d32;
  --color-error: #c62828;
  --color-warning: #f9a825;
  --color-info: #0277bd;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, Arial, sans-serif;
  --font-body: 'IBM Plex Sans', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 32px;
  --font-size-h2: 26px;
  --font-size-h3: 20px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.4;
  --line-height-relaxed: 1.6;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --layout-max-width: 1040px; /* matches approximate central column width */
  --header-nav-height: 48px;
  --border-radius-button: 3px;
  --border-radius-input: 2px;
}

/* Basic reset / body ------------------------------------------------------- */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site-body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-text);
  background-color: var(--color-neutral-page-bg);
}

.page-shell {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  background-color: var(--color-neutral-white);
  min-height: 100vh;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-secondary-navy);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Header ------------------------------------------------------------------- */

.site-header {
  background-color: var(--color-neutral-white);
}

.header-inner {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding: var(--space-2) var(--space-3) var(--space-1);
}

/* Branding (left) */

.header-branding {
  flex: 0 0 auto;
}

.brand-link {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  text-decoration: none;
}

.brand-mark {
  width: 72px;
  height: 72px;
  border-radius: 12px;
  background-color: var(--color-primary-main);
  display: flex;
  align-items: center;
  justify-content: center;
}

.brand-mark-inner {
  width: 52px;
  height: 52px;
  border: 3px solid var(--color-primary-contrast);
  border-radius: 12px;
  color: var(--color-primary-contrast);
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 26px;
}

.brand-text {
  display: flex;
  flex-direction: column;
  text-transform: uppercase;
  font-family: var(--font-heading);
  letter-spacing: 0.08em;
}

.brand-line {
  font-weight: 700;
  font-size: 16px;
}

.brand-line-primary {
  color: var(--color-primary-main);
}

.brand-line-secondary {
  color: #f79035; /* slightly lighter orange as in original mark */
}

/* Right-hand meta / utility */

.header-meta {
  flex: 1 1 auto;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
}

.parent-brand {
  font-family: var(--font-body);
  font-size: 13px;
  margin-bottom: var(--space-1);
}

.parent-brand-prefix,
.parent-brand-suffix {
  color: var(--color-neutral-text-muted);
}

.parent-brand-name {
  color: var(--color-secondary-navy);
  font-weight: 700;
  text-transform: uppercase;
  margin: 0 var(--space-0-5);
}

.header-utility {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.utility-link {
  display: inline-flex;
  align-items: center;
  gap: var(--space-0-5);
  font-size: 13px;
  text-transform: uppercase;
  color: var(--color-neutral-text);
  text-decoration: none;
}

.utility-link:hover,
.utility-link:focus {
  color: var(--color-primary-main);
}

.utility-icon {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-main);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  color: var(--color-primary-main);
}

/* Header search */

.header-search {
  display: flex;
  align-items: stretch;
  border: 1px solid var(--color-neutral-border);
  background-color: var(--color-neutral-white);
}

.header-search-input {
  border: 0;
  padding: 6px 8px;
  min-width: 180px;
  font-size: 13px;
  font-family: var(--font-body);
}

.header-search-input:focus {
  outline: none;
}

.header-search-submit {
  border: 0;
  border-left: 1px solid var(--color-neutral-border);
  background-color: var(--color-primary-main);
  color: var(--color-primary-contrast);
  text-transform: uppercase;
  font-size: 11px;
  font-weight: 600;
  padding: 0 10px;
  cursor: pointer;
}

.header-search-submit:hover,
.header-search-submit:focus {
  background-color: #e37210;
}

/* Primary navigation ------------------------------------------------------- */

.main-nav {
  border-top: 1px solid var(--color-secondary-light-grey);
  border-bottom: 1px solid var(--color-secondary-light-grey);
  background-color: #f1f1f1;
}

.main-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: nowrap;
}

.main-nav-item {
  flex: 1 1 auto;
  border-right: 1px solid var(--color-secondary-light-grey);
}

.main-nav-item:last-child {
  border-right: 0;
}

.main-nav-item > a {
  display: block;
  padding: 14px 10px;
  text-align: center;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #555555;
  text-decoration: none;
}

.main-nav-item > a:hover,
.main-nav-item > a:focus {
  background-color: #e9e9e9;
}

.main-nav-item-active > a {
  background-color: var(--color-primary-main);
  color: var(--color-primary-contrast);
}

.main-nav-item-active > a:hover,
.main-nav-item-active > a:focus {
  background-color: var(--color-primary-main);
}

/* Content wrapper ---------------------------------------------------------- */

.site-content {
  padding: var(--space-4) var(--space-3) var(--space-5);
  background-color: var(--color-neutral-white);
}

/* Headings (generic) */

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

/* Buttons (for use within #content; none instantiated in framework markup) */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 20px;
  border-radius: var(--border-radius-button);
  border: none;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  cursor: pointer;
  text-decoration: none;
}

.btn-primary {
  background-color: var(--color-primary-main);
  color: var(--color-primary-contrast);
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #e37210;
}

.btn-secondary {
  background-color: var(--color-neutral-panel);
  color: #555555;
}

.btn-secondary:hover,
.btn-secondary:focus {
  background-color: #e9e9e9;
}

.btn .btn-icon-right {
  margin-left: var(--space-1);
}

/* Hero / slider patterns (for pages that need them) ------------------------ */

.hero-slider {
  position: relative;
  margin: 0 calc(-1 * var(--space-3));
}

.hero-slide {
  position: relative;
}

.hero-slide-image {
  display: block;
  width: 100%;
}

.hero-slide-overlay {
  position: absolute;
  left: var(--space-4);
  top: var(--space-4);
  max-width: 420px;
  color: var(--color-neutral-white);
}

.hero-slide-overlay h1,
.hero-slide-overlay h2,
.hero-slide-overlay h3 {
  color: var(--color-neutral-white);
}

.hero-slide-overlay p {
  font-size: 15px;
  line-height: var(--line-height-relaxed);
}

.hero-pagination {
  position: absolute;
  right: var(--space-4);
  bottom: 0;
  display: flex;
  border-top: 1px solid var(--color-secondary-light-grey);
}

.hero-pagination-button {
  min-width: 32px;
  padding: 8px 10px;
  text-align: center;
  font-size: 12px;
  border-left: 1px solid var(--color-secondary-light-grey);
  background-color: var(--color-neutral-white);
  color: var(--color-neutral-text-muted);
  cursor: pointer;
}

.hero-pagination-button:first-child {
  border-left: none;
}

.hero-pagination-button.is-active {
  background-color: var(--color-primary-main);
  color: var(--color-primary-contrast);
}

/* Footer ------------------------------------------------------------------- */

.site-footer {
  border-top: 4px solid var(--color-primary-main);
  background-color: var(--color-neutral-panel);
}

.footer-inner {
  padding: var(--space-3) var(--space-3) var(--space-2);
}

.footer-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--space-2);
}

.footer-brand-link {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  text-decoration: none;
}

.footer-brand-mark {
  width: 40px;
  height: 40px;
  border-radius: 8px;
  background-color: var(--color-primary-main);
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-brand-mark-inner {
  width: 26px;
  height: 26px;
  border: 2px solid var(--color-primary-contrast);
  border-radius: 6px;
  color: var(--color-primary-contrast);
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 14px;
}

.footer-brand-text {
  font-family: var(--font-heading);
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: #555555;
}

.footer-nav-wrapper {
  border-top: 1px solid var(--color-secondary-light-grey);
  border-bottom: 1px solid var(--color-secondary-light-grey);
  padding: var(--space-1) 0;
  margin-bottom: var(--space-1);
}

.footer-nav {
  display: block;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1) var(--space-3);
}

.footer-link-item a {
  font-size: 13px;
  color: var(--color-neutral-text);
}

.footer-link-item a:hover,
.footer-link-item a:focus {
  color: var(--color-primary-main);
}

.footer-meta {
  margin-top: var(--space-1);
  font-size: var(--font-size-small);
  color: var(--color-neutral-text-muted);
}

.footer-copy {
  margin: 0;
}

/* Responsive adjustments --------------------------------------------------- */

@media (max-width: 960px) {
  .header-inner {
    flex-direction: column;
    align-items: stretch;
    gap: var(--space-2);
  }

  .header-meta {
    align-items: flex-start;
  }

  .header-utility {
    width: 100%;
    justify-content: space-between;
  }

  .main-nav-list {
    flex-wrap: wrap;
  }

  .main-nav-item {
    flex: 1 0 50%;
  }

  .site-content {
    padding: var(--space-3) var(--space-2) var(--space-4);
  }

  .hero-slider {
    margin: 0 calc(-1 * var(--space-2));
  }
}

@media (max-width: 640px) {
  .brand-link {
    align-items: flex-start;
  }

  .brand-mark {
    width: 56px;
    height: 56px;
  }

  .brand-mark-inner {
    width: 40px;
    height: 40px;
    font-size: 20px;
  }

  .header-utility {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
  }

  .header-search-input {
    min-width: 0;
    width: 100%;
  }

  .main-nav-item {
    flex: 1 0 100%;
  }

  .footer-links {
    flex-direction: column;
  }
}
